import { Injectable, HttpException, HttpStatus } from '@nestjs/common';
import {
  NestMiddleware,
  MiddlewareFunction
} from '@nestjs/common/interfaces/middlewares';
import * as multer from 'multer';
import * as path from 'path';

@Injectable()
export class FileUploadMiddleware implements NestMiddleware {
  resolve() {
    return (req, res, next) => {
      const storage = multer.diskStorage({
        destination: (req, file, cb) => {
          cb(null, './uploads/images');
        },
        filename: (req, file, cb) => {
          cb(
            null,
            `${file.fieldname}-${Date.now()}${path
              .extname(file.originalname)
              .toLowerCase()}`
          );
        }
      });

      function imageFilter(request, file, cb) {
        // accept image only
        if (!file.originalname.match(/\.(jpg|jpeg|png|gif)$/i)) {
          return cb('Only image files are allowed!', false);
        }
        cb(null, true);
      }

      const upload = multer({
        storage: storage,
        fileFilter: imageFilter
      }).any();
      req.upload = upload;

      next();
    };
  }
}

import { Injectable } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { DiskConfig, DiskConfigName } from '../config/disk.config';
import { extname, resolve } from 'path';

@Injectable()
export class FilesService {
  constructor(private readonly configService: ConfigService) {}

  getDiskPath() {
    const diskConfig =
      this.configService.getOrThrow<DiskConfig>(DiskConfigName);
    const diskPath = resolve(__dirname, '../..', diskConfig.path);
    return diskPath;
  }

  getFileName(file: Express.Multer.File) {
    const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1e9);
    const ext = extname(file.originalname).toLowerCase();
    const name = file.originalname.replace(/\s/g, '-').replace(ext, '');
    const fileName = `${name}_${uniqueSuffix}${ext}`;
    return fileName;
  }

  getImageCacheDuration() {
    const diskConfig =
      this.configService.getOrThrow<DiskConfig>(DiskConfigName);
    return diskConfig.imageCacheDuration;
  }
}

